import{_ as t,c as i,a1 as a,o as s}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Tools","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/8-social-engineering/X-Tools.md","filePath":"categories/ethical-hacking-labs/8-social-engineering/X-Tools.md"}'),n={name:"categories/ethical-hacking-labs/8-social-engineering/X-Tools.md"};function r(o,e,h,p,l,c){return s(),i("div",null,e[0]||(e[0]=[a('<h1 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h1><h2 id="detect-phishing-sites-using-netcraft-extension" tabindex="-1">Detect Phishing sites using NetCraft extension <a class="header-anchor" href="#detect-phishing-sites-using-netcraft-extension" aria-label="Permalink to &quot;Detect Phishing sites using NetCraft extension&quot;">​</a></h2><p>The Netcraft anti-phishing browser extension provides comprehensive site information and phishing protection when browsing the web. Users can also use the extension to report URLs they believe to be malicious to Netcraft.</p><p><a href="https://netcraft.app/browser-extension/" target="_blank" rel="noreferrer">https://netcraft.app/browser-extension/</a><img src="https://netcraft.app/assets/img/screenshots/extension/blocked.png" alt="NetCraft"></p><h2 id="detect-phishing-using-phishtank" tabindex="-1">Detect Phishing using PhishTank <a class="header-anchor" href="#detect-phishing-using-phishtank" aria-label="Permalink to &quot;Detect Phishing using PhishTank&quot;">​</a></h2><p>PhishTank is a collaborative clearing house for data and information about phishing on the Internet. Also, PhishTank provides an open API for developers and researchers to integrate anti-phishing data into their applications at no charge.</p><p><a href="https://www.phishtank.com/" target="_blank" rel="noreferrer">https://www.phishtank.com/</a></p><h2 id="wifiphisher" tabindex="-1">Wifiphisher <a class="header-anchor" href="#wifiphisher" aria-label="Permalink to &quot;Wifiphisher&quot;">​</a></h2><p>Wifiphisher is a security tool that mounts automated phishing attacks against Wi-Fi networks in order to obtain credentials or infect the victims with ‘malware’. It is a social engineering attack that can be used to obtain WPA/WPA2 secret passphrases and unlike other methods, it does not require any brute forcing. After achieving a man-in-the-middle position using the Evil Twin attack, Wifiphisher redirects all HTTP requests to an attacker-controlled phishing page.</p><p><a href="https://tools.kali.org/wireless-attacks/wifiphisher" target="_blank" rel="noreferrer">https://tools.kali.org/wireless-attacks/wifiphisher</a></p><h2 id="spf-speedphish-framework" tabindex="-1">SPF - SpeedPhish Framework <a class="header-anchor" href="#spf-speedphish-framework" aria-label="Permalink to &quot;SPF - SpeedPhish Framework&quot;">​</a></h2><p>SPF (SpeedPhish Framework) is a python tool designed to allow for quick recon and deployment of simple social engineering phishing exercises.</p><p><a href="https://github.com/tatanus/SPF" target="_blank" rel="noreferrer">https://github.com/tatanus/SPF</a></p>',13)]))}const f=t(n,[["render",r]]);export{d as __pageData,f as default};
